var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"Huh…","TWN":"這是……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……재미있군요.","JPN":"……面白いですね。","ENG":"Well, this is interesting…","TWN":"……真有意思。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국의 기밀 함선인 방주는 클리파 차원과 현실의 통로를 막는 역할을 하고 있죠.","JPN":"管理局の機密艦船である箱舟は、クリファ次元と現実の通路を塞ぐ役割を果たしています。","ENG":"The Administration used its highly-classified Ark to block the path between Qlipha dimension and our world.","TWN":"管理局機密艦船 方舟的作用是堵住逆卡巴拉次元和現世間的通道。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"클리포트의 마왕과 그 사도들의 힘을 억제하기 위해서요.","JPN":"クリフォトの魔王とその使徒たちの力を抑制するためです。","ENG":"This was to deter the Demon Lords of Qliphoth and their Apostles.","TWN":" 目的是克制魔王和那些使徒的力量。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 통로에 간섭할 수 있다면, 반대로 활용할 수도 있다는 뜻입니다.","JPN":"しかし、通路に干渉できるということは、逆に利用することもできるということです。","ENG":"But if one can intervene in this path, that means it's also possible to exploit this.","TWN":"但若是可以干涉通道，那就表示也可以逆向操作。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"방주를 침식시켜 클리파 차원과의 통로를 확장하는 데 사용하다니…….","JPN":"箱舟を侵食させて、クリファ次元との通路を拡張するために使うなんて……","ENG":"Someone got the idea to corrupt the Ark itself to expand the path to Qlipha…","TWN":"竟然想到侵蝕方舟來擴充和逆卡巴拉次元間的通道……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"누구인지는 몰라도 꽤 참신한 발상을 떠올렸네요.","JPN":"誰かはわかりませんが、かなり斬新な発想ですね。","ENG":"I've got to say it was pretty innovative, whoever it was that thought of it.","TWN":"雖然不知道那個人是誰，但他真是天才。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……방주에 대해 꽤 잘 알고 있군.","JPN":"……箱舟についてかなり詳しいようだな。","ENG":"…You seem very familiar with the Ark.","TWN":"……你很清楚方舟的事嘛！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러고 보니 이수연, 너도 방주의 존재에 대해 알고 나를 여기로 보냈지.","JPN":"そういえばカナミ、お前も箱舟の存在について知った上で私をここに送ったな。","ENG":"Come to think of it, you sent me here in full knowledge of the Ark as well, Sooyeon.","TWN":"這麼說來，李秀妍你也是知道方舟的事，才會把我弄來這裡的吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그것도 이 녀석이 알려 준 거냐?","JPN":"それもこいつが教えてくれたのか？","ENG":"Did you hear about that from this fool?","TWN":"也是這傢伙告訴你的嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……글쎄요, 어떨까요?","JPN":"……さあ、どうですかね。","ENG":"Well... What do you think?","TWN":"……這個嘛？你說呢？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"코핀 시리즈가 방주라는 건 구 관리국 시절에도 기밀 중의 기밀이었다.","JPN":"コフィンシリーズが箱舟というのは、旧管理局時代の機密中の機密だった。","ENG":"The fact that the Coffin series are Arks was one of the closest held secrets even during the Old Administration.","TWN":"科芬系列是方舟的事，在舊管理局時期也是機密中的機密。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나유빈, 넌 대체 어디까지 알고 있는 거지?","JPN":"イチノセ・カオル、お前はいったいどこまで知っているんだ？","ENG":"How much do you know exactly, Na Yubin?","TWN":"羅瑜斌，你到底知道多少？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……아주 먼 옛날, 최초의 세계에서 만들어진 관리국의 첫 번째 차원함선들이라는 것 정도는 알고 있습니다.","JPN":"……はるか昔、最初の世界で作られた管理局の最初の次元艦船ということぐらいは知っています。","ENG":"Only that they were the first dimensional ships built by the Administration long, long ago… in the very first world.","TWN":"……就很久以前，管理局在起初世界中首次打造的那些次元艦船。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 단순히 <color=#ffd34c>심도</color>로 나눠진 이면세계들이 아니라, 완전한 세계선 이동이 가능하다는 것도 말이죠.","JPN":"そして単純に<color=#ffd34c>深度</color>で分かれた裏世界ではなく、完全な世界線移動が可能だということもですね。","ENG":"And also that they can jump between entire worldlines, instead of merely diving to different <color=#ffd34c>depths</color> in the Counterside.","TWN":"而且那些不是單純以<color=#ffd34c>深度</color>區分的異界，而是可以完整的世界線移動。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그걸, 네가 어떻게……?","JPN":"そんなこと、お前がどうして……？","ENG":"How… How would you know that?","TWN":"你怎麼會知道……？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"펜릴 전대에 있을 때 어떤 사람과 만난 적이 있습니다.","JPN":"フェンリル戦隊にいた時、ある人と出会ったんです。","ENG":"I met someone when I was with Fenrir.","TWN":"我在芬里爾戰隊時曾到遇到一個人。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};